-        int e = errno;
-        tty->print("Can't open JVMCI shared library error report file. Error: ");
-        tty->print_raw_cr(os::strerror(e));
-        tty->print_cr("JVMCI shared library error report will be written to console.");
-
-        // See notes in VMError::report_and_die about hard coding tty to 1
-        log_fd = 1;
-      }
-    }
-    _fatal_log_fd = log_fd;
-  } else if (_first_error_tid != current_thread_id) {
-    // This is not the first thread reporting a libjvmci error
-    tty->print_cr("[thread %zd also had an error in the JVMCI native library]",
-                    current_thread_id);
-
-    // Fatal error reporting is single threaded so just block this thread.
-    os::infinite_sleep();
-  }
-  fdStream log(_fatal_log_fd);
-  log.write(buf, count);
-  log.flush();
-}

