-    // Loop until there is something in the queue.
-    do {
-      THREAD->sleep(100);
-      qsize = CompileBroker::queue_size(CompLevel_full_optimization);
-    } while (!_bootstrap_compilation_request_handled && first_round && qsize == 0);
-    first_round = false;
-    if (PrintBootstrap) {
-      while (z < (_methods_compiled / 100)) {
-        ++z;
-        tty->print_raw(".");
