-    }
-  } while (qsize != 0);
-
-  if (PrintBootstrap) {
-    tty->print_cr(" in " JLONG_FORMAT " ms (compiled %d methods)",
-                  (jlong)nanos_to_millis(os::javaTimeNanos() - start), _methods_compiled);
