-    case T_LONG:        _jca->push_long(arg->long_field(box_offset));   break;
-    case T_FLOAT:       _jca->push_float(arg->float_field(box_offset));    break;
-    case T_DOUBLE:      _jca->push_double(arg->double_field(box_offset));  break;
