-static void resync_vframestream_to_compiled_frame(vframeStream& vfst, intptr_t* stack_pointer, int vframe_id, JavaThread* thread, TRAPS) {
-  vfst = vframeStream(thread);
-  while (vfst.frame_id() != stack_pointer && !vfst.at_end()) {
-    vfst.next();
