-    ObjectValue* sv = (ObjectValue*) scope_objects->at(i);
-    if (sv->value().is_null()) {
-      if (unallocated == nullptr) {
-        unallocated = new GrowableArray<ScopeValue*>(scope_objects->length());
-      }
-      unallocated->append(sv);
