-          last_line = cursor;
-        } else if (line < max_lines) {
-          JVMCI_event_1("%s", cursor);
-        }
-        cursor = eol + 1;
-      }
-      line++;
-    }
-    if (last_line != nullptr) {
-      if (line > max_lines) {
-        JVMCI_event_1("%s [elided %d more stack trace lines]", last_line, line - max_lines);
