-// Swaps the elements in `array` at index `a` and index `b`
-static void swap(GrowableArray<oop*>* array, int a, int b) {
-  oop* tmp = array->at(a);
-  array->at_put(a, array->at(b));
-  array->at_put(b, tmp);
-}
