-    private void writeJavaValue(JavaValue value, JavaKind kind) {
-        if (value == Value.ILLEGAL) {
-            writeTag(ILLEGAL);
-        } else if (value == JavaConstant.NULL_POINTER || value instanceof HotSpotCompressedNullConstant) {
-            if (JavaKind.Object != kind) {
