-         */
-        private static volatile Internals instance;
-
-        static Internals instance() {
-            Internals result = instance;
-            if (result == null) {
-                synchronized (VMState.class) {
-                    result = instance;
-                    if (result == null) {
-                        instance = result = new Internals();
-                    }
-                }
-            }
