-    private void runTest(TestCase tcase, Lookup lookup) {
-        System.out.println(tcase);
-        ResolvedJavaType metaspaceKlass;
-        try {
-            metaspaceKlass = lookup.lookupType(tcase.className,
-                    tcase.accessing, tcase.resolve);
