-            return new AArch64TestAssembler(codeCache, config);
-        } else if (arch instanceof RISCV64) {
-            return new RISCV64TestAssembler(codeCache, config);
-        } else {
-            Assert.fail("unsupported architecture");
-            return null;
-        }
-    }
