-    @Override
-    public void emitPrologue() {
-        // Must be patchable by NativeJump::patch_verified_entry
-        emitNop();
-        if (config.ropProtection) {
-            code.emitInt(0xf94003df);  // ldr xzr, [x30]
-            code.emitInt(0xd503231f);  // paciaz
