-        code.emitInt(0xa9bf7bfd);      // stp x29, x30, [sp, #-16]!
-        code.emitInt(0x910003fd);      // mov x29, sp
-
-        emitNMethodEntryBarrier();
-
-        setDeoptRescueSlot(newStackSlot(AArch64Kind.QWORD));
-    }
