-        private static int indexOf(byte[] b, int index, String find) {
-            for (int i = index; i < b.length; i++) {
-                boolean match = true;
-                for (int j = i; j < i + find.length(); j++) {
-                    if (b[j] != (byte) find.charAt(j - i)) {
-                        match = false;
-                        break;
-                    }
-                }
-                if (match) {
-                    return i;
-                }
-            }
-            return -1;
-        }
